package org.eclipse.rdf4j.query.algebra.equivalence.internal;

import static org.junit.jupiter.api.Assertions.assertEquals;
import static org.junit.jupiter.api.Assertions.assertFalse;
import static org.junit.jupiter.api.Assertions.assertTrue;

import java.util.ArrayDeque;
import java.util.Deque;
import java.util.List;

import org.eclipse.rdf4j.model.IRI;
import org.eclipse.rdf4j.model.TripleTerm;
import org.eclipse.rdf4j.model.ValueFactory;
import org.eclipse.rdf4j.model.impl.SimpleValueFactory;
import org.eclipse.rdf4j.query.algebra.EmptySet;
import org.eclipse.rdf4j.query.algebra.SingletonSet;
import org.eclipse.rdf4j.query.algebra.Union;
import org.eclipse.rdf4j.query.algebra.equivalence.BindingSetSnapshot;
import org.eclipse.rdf4j.query.algebra.equivalence.CheckOptions;
import org.eclipse.rdf4j.query.algebra.equivalence.Counterexample;
import org.eclipse.rdf4j.query.algebra.equivalence.EvaluationCase;
import org.eclipse.rdf4j.query.algebra.equivalence.EvaluationOutcome;
import org.eclipse.rdf4j.query.algebra.equivalence.SemanticsTarget;
import org.eclipse.rdf4j.query.impl.MapBindingSet;
import org.junit.jupiter.api.Test;

class BoundedCounterexampleFinderTest {
	private static final ValueFactory VF = SimpleValueFactory.getInstance();
	private static final IRI SUBJECT = VF.createIRI("urn:test:subject");
	private static final IRI PREDICATE = VF.createIRI("urn:test:predicate");

	@Test
	void configuredCaseLimitAndSearchCountsAreExact() {
		CheckOptions options = CheckOptions.builder()
				.boundedCounterexampleSearch(true)
				.maxEvaluationCases(1)
				.addEvaluationCase(EvaluationCase.builder("first").build())
				.addEvaluationCase(EvaluationCase.builder("second").build())
				.build();

		BoundedCounterexampleFinder.SearchResult result = new BoundedCounterexampleFinder(options)
				.find(new SingletonSet(), new SingletonSet());

		assertFalse(result.getCounterexample().isPresent());
		assertEquals(1, result.getEvaluatedCases());
		assertEquals(0, result.getSkippedCases());
		assertEquals("no distinguishing finite model was found within the configured bounds", result.getReason());
	}

	@Test
	void incompleteEvaluationIsCountedAsSkipped() {
		CheckOptions options = CheckOptions.builder()
				.maxResultRows(1)
				.addEvaluationCase(EvaluationCase.builder("empty").build())
				.build();

		BoundedCounterexampleFinder.SearchResult result = new BoundedCounterexampleFinder(options)
				.find(new Union(new SingletonSet(), new SingletonSet()), new SingletonSet());

		assertFalse(result.getCounterexample().isPresent());
		assertEquals(0, result.getEvaluatedCases());
		assertEquals(1, result.getSkippedCases());
	}

	@Test
	void specificationCasesWithBindingsAreCountedAsIncompatible() {
		MapBindingSet bindings = new MapBindingSet();
		bindings.setBinding("x", SUBJECT);
		CheckOptions options = CheckOptions.builder()
				.semanticsTarget(SemanticsTarget.SPARQL_1_1)
				.addEvaluationCase(EvaluationCase.builder("correlated").initialBindings(bindings).build())
				.build();

		BoundedCounterexampleFinder.SearchResult result = new BoundedCounterexampleFinder(options)
				.find(new SingletonSet(), new EmptySet());

		assertFalse(result.getCounterexample().isPresent());
		assertEquals(0, result.getEvaluatedCases());
		assertEquals(1, result.getSkippedCases());
		assertEquals(
				"all configured evaluation cases were incompatible with the selected semantic target",
				result.getReason());
	}

	@Test
	void rejectedSpecificationCaseRetainsFirstValidationReason() {
		TripleTerm triple = VF.createTripleTerm(SUBJECT, PREDICATE, VF.createLiteral("object"));
		EvaluationCase rdf12 = EvaluationCase.builder("RDF 1.2")
				.addStatement(VF.createStatement(SUBJECT, PREDICATE, triple))
				.build();
		CheckOptions options = CheckOptions.builder()
				.semanticsTarget(SemanticsTarget.SPARQL_1_1)
				.addEvaluationCase(rdf12)
				.build();

		BoundedCounterexampleFinder.SearchResult result = new BoundedCounterexampleFinder(options)
				.find(new SingletonSet(), new EmptySet());

		assertEquals(0, result.getEvaluatedCases());
		assertEquals(1, result.getSkippedCases());
		assertTrue(result.getReason().contains("RDF 1.2 triple term"));
	}

	@Test
	void specificationCaseStopsBeforeRuntimeEvaluation() {
		CheckOptions options = CheckOptions.builder()
				.semanticsTarget(SemanticsTarget.SPARQL_1_2_DRAFT)
				.addEvaluationCase(EvaluationCase.builder("empty").build())
				.build();

		BoundedCounterexampleFinder.SearchResult result = new BoundedCounterexampleFinder(options)
				.find(new SingletonSet(), new EmptySet());

		assertEquals(0, result.getEvaluatedCases());
		assertEquals(0, result.getSkippedCases());
		assertEquals(
				"the formal specification oracle is not yet available; RDF4J runtime evaluation cannot establish "
						+ "SPARQL_1_2_DRAFT counterexamples",
				result.getReason());
	}

	@Test
	void runtimeWitnessCarriesDeclaredAndFallbackOracleVersions() {
		String property = "rdf4j.equivalence.runtimeOracleVersion";
		String previous = System.getProperty(property);
		try {
			System.setProperty(property, "RDF4J commit abc123");
			Counterexample declared = witnessWithEmptyCase();
			assertEquals("RDF4J commit abc123", declared.getOracleVersion());

			System.clearProperty(property);
			Counterexample fallback = witnessWithEmptyCase();
			String implementationVersion = Rdf4jEvaluator.class.getPackage().getImplementationVersion();
			String expected = "RDF4J "
					+ (implementationVersion == null ? "development build" : implementationVersion)
					+ "; source commit unpinned";
			assertEquals(expected, fallback.getOracleVersion());
			assertEquals(SemanticsTarget.RDF4J_RUNTIME, fallback.getSemanticsTarget());
		} finally {
			if (previous == null) {
				System.clearProperty(property);
			} else {
				System.setProperty(property, previous);
			}
		}
	}

	@Test
	void incompleteWitnessReplayIsSkipped() {
		Deque<EvaluationAttempt> attempts = new ArrayDeque<>(List.of(
				completedEmpty(),
				completedOneRow(),
				EvaluationAttempt.incomplete("repeat limit"),
				completedOneRow()));
		BoundedCounterexampleFinder.SearchResult result = finderWithScript(attempts)
				.find(new SingletonSet(), new EmptySet());

		assertFalse(result.getCounterexample().isPresent());
		assertEquals(1, result.getEvaluatedCases());
		assertEquals(1, result.getSkippedCases());
		assertTrue(attempts.isEmpty());
	}

	@Test
	void unstableWitnessReplayIsSkipped() {
		Deque<EvaluationAttempt> attempts = new ArrayDeque<>(List.of(
				completedEmpty(),
				completedOneRow(),
				completedOneRow(),
				completedOneRow()));
		BoundedCounterexampleFinder.SearchResult result = finderWithScript(attempts)
				.find(new SingletonSet(), new EmptySet());

		assertFalse(result.getCounterexample().isPresent());
		assertEquals(1, result.getEvaluatedCases());
		assertEquals(1, result.getSkippedCases());
		assertTrue(attempts.isEmpty());
	}

	private static Counterexample witnessWithEmptyCase() {
		CheckOptions options = CheckOptions.builder()
				.addEvaluationCase(EvaluationCase.builder("empty").build())
				.build();
		BoundedCounterexampleFinder.SearchResult result = new BoundedCounterexampleFinder(options)
				.find(new SingletonSet(), new EmptySet());
		assertEquals(1, result.getEvaluatedCases());
		assertEquals(0, result.getSkippedCases());
		return result.getCounterexample().orElseThrow();
	}

	private static BoundedCounterexampleFinder finderWithScript(Deque<EvaluationAttempt> attempts) {
		CheckOptions options = CheckOptions.builder()
				.addEvaluationCase(EvaluationCase.builder("scripted").build())
				.build();
		return new BoundedCounterexampleFinder(options,
				(expression, evaluationCase, maxRows) -> attempts.removeFirst());
	}

	private static EvaluationAttempt completedEmpty() {
		return EvaluationAttempt.completed(EvaluationOutcome.success(List.of()));
	}

	private static EvaluationAttempt completedOneRow() {
		MapBindingSet row = new MapBindingSet();
		row.setBinding("x", SUBJECT);
		return EvaluationAttempt.completed(EvaluationOutcome.success(List.of(BindingSetSnapshot.copyOf(row))));
	}
}
